class Solution {
public:
    vector<int> transposeArray(vector<int>& nums) {
        sort(nums.begin(), nums.end());
        vector<int> result(nums.size());
        int j = 0;
        for (int i = 0; i < nums.size(); i++) {
            if (nums[i] % 2 == 0) {
                result[j++] = 0;
            } else {
                result[j++] = nums[i];
            }
        }
        return result;
    }
};
